		`,roles:["Graphics Programming","UI Programming"],types:["University Project","Group Project (4 Members)"],created:"August 2019 - January 2020 (6 Months)",tools:["Java","OpenCV","OpenGL"],headerImages:["1.webp","2.webp","3.webp"],features:[{media:"videos/6.webm",description:`
